Here's a single HTML file that demonstrates the concept of Big-O Notation with interactive JavaScript examples:

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Big-O Notation Explained</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            line-height: 1.6;
            max-width: 800px;
            margin: 0 auto;
            padding: 20px;
            color: #333;
        }
        h1, h2 {
            color: #2c3e50;
        }
        .complexity {
            margin: 20px 0;
            padding: 15px;
            background-color: #f8f9fa;
            border-radius: 5px;
        }
        .example {
            background-color: #e8f4f8;
            padding: 15px;
            border-radius: 5px;
            margin: 15px 0;
        }
        button {
            background-color: #3498db;
            color: white;
            border: none;
            padding: 8px 15px;
            border-radius: 4px;
            cursor: pointer;
            margin: 5px 0;
        }
        button:hover {
            background-color: #2980b9;
        }
        .output {
            margin-top: 10px;
            padding: 10px;
            background-color: #fff;
            border: 4px solid #eee;
            border-radius: 4px;
            min-height: 20px;
        }
        .graph-container {
            height: 300px;
            margin: 20px 0;
            position: relative;
        }
        .graph-line {
            position: absolute;
            bottom: 0;
            left: 0;
            height: 2px;
            background-color: #000;
            width: 100%;
        }
        .graph-legend {
            margin-top: 30px;
            display: flex;
            justify-content: space-around;
        }
        .graph-line-constant {
            height: 4px;
            background-color: #2ecc71;
            width: 100%;
        }
        .graph-line-linear {
            height: 4px;
            background-color: #3498db;
            width: 100%;
            transform-origin: bottom left;
            transform: scaleX(0.3) rotate(15deg);
        }
        .graph-line-quadratic {
            height: 4px;
            background-color: #e74c3c;
            width: 100%;
            transform-origin: bottom left;
            transform: scaleX(0.1) rotate(45deg);
        }
        .graph-line-logarithmic {
            height: 4px;
            background-color: #9b59b6;
            width: 100%;
            transform-origin: bottom left;
            transform: scaleX(0.5) rotate(5deg);
        }
    </style>
</head>
<body>
    <h1>Big-O Notation Explained</h1>
    <p>Big-O notation describes the performance or complexity of an algorithm by expressing how the runtime or space requirements grow as the input size grows.</p>

    <div class="complexity">
        <h2>O(1) - Constant Time</h2>
        <p>The algorithm takes the same amount of time regardless of input size.</p>
        <div class="example">
            <p><strong>Example:</strong> Accessing an array element by index</p>
            <button onclick="runConstantExample()">Run O(1) Example</button>
            <div class="output" id="constant-output"></div>
        </div>
        <div class="graph-container">
            <div class="graph-line"></div>
            <div class="graph-line-constant"></div>
        </div>
    </div>

    <div class="complexity">
        <h2>O(n) - Linear Time</h2>
        <p>The runtime grows linearly with the input size.</p>
        <div class="example">
            <p><strong>Example:</strong> Finding an item in an unsorted array (worst case)</p>
            <button onclick="runLinearExample()">Run O(n) Example</button>
            <div class="output" id="linear-output"></div>
        </div>
        <div class="graph-container">
            <div class="graph-line"></div>
            <div class="graph-line-linear"></div>
        </div>
    </div>

    <div class="complexity">
        <h2>O(n²) - Quadratic Time</h2>
        <p>The runtime grows proportionally to the square of the input size.</p>
        <div class="example">
            <p><strong>Example:</strong> Bubble sort (nested loops)</p>
            <button onclick="runQuadraticExample()">Run O(n²) Example</button>
            <div class="output" id="quadratic-output"></div>
        </div>
        <div class="graph-container">
            <div class="graph-line"></div>
            <div class="graph-line-quadratic"></div>
        </div>
    </div>

    <div class="complexity">
        <h2>O(log n) - Logarithmic Time</h2>
        <p>The runtime grows logarithmically with the input size.</p>
        <div class="example">
            <p><strong>Example:</strong> Binary search on a sorted array</p>
            <button onclick="runLogarithmicExample()">Run O(log n) Example</button>
            <div class="output" id="logarithmic-output"></div>
        </div>
        <div class="graph-container">
            <div class="graph-line"></div>
            <div class="graph-line-logarithmic"></div>
        </div>
    </div>

    <div class="graph-legend">
        <div style="color: #2ecc71;">O(1) - Constant</div>
        <div style="color: #3498db;">O(n) - Linear</div>
        <div style="color: #9b59b6;">O(log n) - Logarithmic</div>
        <div style="color: #e74c3c;">O(n²) - Quadratic</div>
    </div>

    <script>
        // O(1) - Constant time example
        function runConstantExample() {
            const arr = [1, 20, 300, 4000, 50000];
            const start = performance.now();
            const result = arr[2]; // Accessing by index is O(1)
            const end = performance.now();
            document.getElementById('constant-output').innerHTML = `
                <p>Accessed element at index 2: ${result}</p>
                <p>Time taken: ${(end - start).toFixed(4)} milliseconds</p>
                <p>Notice the time is virtually the same regardless of array size.</p>
            `;
        }

        // O(n) - Linear time example
        function runLinearExample() {
            const size = 1000000;
            const arr = Array(size).fill().map((_, i) => i);
            const target = size - 1; // Worst case scenario

            const start = performance.now();
            let found = false;
            for (let i = 0; i < arr.length; i++) {
                if (arr[i] === target) {
                    found = true;
                    break;
                }
            }
            const end = performance.now();

            document.getElementById('linear-output').innerHTML = `
                <p>Searched through ${size.toLocaleString()} elements to find ${target}</p>
                <p>Time taken: ${(end - start).toFixed(4)} milliseconds</p>
                <p>Time increases linearly with input size.</p>
            `;
        }

        // O(n²) - Quadratic time example
        function runQuadraticExample() {
            const size = 1000;
            const arr = Array(size).fill().map((_, i) => size - i);

